import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"고급 기능: 다중 계정 관리 | Antigravity Auth","description":"Antigravity Auth 플러그인의 고급 기능을 마스터합니다. 다중 계정 로드 밸런싱, 스마트 계정 선택, 속도 제한 처리, 세션 복구, 요청 변환 등 핵심 메커니즘을 심층적으로 학습합니다.","frontmatter":{"title":"고급 기능: 다중 계정 관리 | Antigravity Auth","sidebarTitle":"다중 계정 마스터하기","subtitle":"고급 기능: 다중 계정 관리","description":"Antigravity Auth 플러그인의 고급 기능을 마스터합니다. 다중 계정 로드 밸런싱, 스마트 계정 선택, 속도 제한 처리, 세션 복구, 요청 변환 등 핵심 메커니즘을 심층적으로 학습합니다.","order":3},"headers":[],"relativePath":"ko/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"ko/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"ko/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function o(n,a,h,s,u,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="고급-기능" tabindex="-1">고급 기능 <a class="header-anchor" href="#고급-기능" aria-label="Permalink to &quot;고급 기능&quot;">​</a></h1><p>본 섹션에서는 Antigravity Auth 플러그인의 고급 기능을 심층적으로 다룹니다. 다중 계정 로드 밸런싱, 스마트 계정 선택, 속도 제한 처리, 세션 복구, 요청 변환 등 핵심 메커니즘을 학습합니다. 할당량 활용 최적화부터 복잡한 문제 해결까지, 필요한 모든 내용을 다룹니다.</p><h2 id="사전-요구사항" tabindex="-1">사전 요구사항 <a class="header-anchor" href="#사전-요구사항" aria-label="Permalink to &quot;사전 요구사항&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">시작하기 전에 확인하세요</p><ul><li>✅ <a href="./../start/quick-install/">빠른 설치</a>를 완료하고 첫 번째 계정을 성공적으로 추가</li><li>✅ <a href="./../start/first-auth-login/">첫 번째 인증</a>을 완료하고 OAuth 흐름 이해</li><li>✅ <a href="./../start/first-request/">첫 번째 요청</a>을 완료하고 플러그인 정상 작동 확인</li></ul></div><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><h3 id="_1-다중-계정-설정" tabindex="-1">1. <a href="./multi-account-setup/">다중 계정 설정</a> <a class="header-anchor" href="#_1-다중-계정-설정" aria-label="Permalink to &quot;1. [다중 계정 설정](./multi-account-setup/)&quot;">​</a></h3><p>여러 Google 계정을 설정하여 할당량 풀링과 로드 밸런싱을 구현합니다.</p><ul><li>여러 계정을 추가하여 전체 할당량 한도 증가</li><li>이중 할당량 시스템 이해 (Antigravity + Gemini CLI)</li><li>시나리오에 맞는 적절한 계정 수 선택</li></ul><h3 id="_2-계정-선택-전략" tabindex="-1">2. <a href="./account-selection-strategies/">계정 선택 전략</a> <a class="header-anchor" href="#_2-계정-선택-전략" aria-label="Permalink to &quot;2. [계정 선택 전략](./account-selection-strategies/)&quot;">​</a></h3><p>sticky, round-robin, hybrid 세 가지 계정 선택 전략의 모범 사례를 마스터합니다.</p><ul><li>1개 계정 → sticky 전략으로 프롬프트 캐시 유지</li><li>2-3개 계정 → hybrid 전략으로 스마트 요청 분배</li><li>4개 이상 계정 → round-robin 전략으로 처리량 극대화</li></ul><h3 id="_3-속도-제한-처리" tabindex="-1">3. <a href="./rate-limit-handling/">속도 제한 처리</a> <a class="header-anchor" href="#_3-속도-제한-처리" aria-label="Permalink to &quot;3. [속도 제한 처리](./rate-limit-handling/)&quot;">​</a></h3><p>속도 제한 감지, 자동 재시도, 계정 전환 메커니즘을 이해합니다.</p><ul><li>5가지 유형의 429 오류 구분</li><li>자동 재시도의 지수 백오프 알고리즘 이해</li><li>다중 계정 시나리오에서의 자동 전환 로직 마스터</li></ul><h3 id="_4-세션-복구" tabindex="-1">4. <a href="./session-recovery/">세션 복구</a> <a class="header-anchor" href="#_4-세션-복구" aria-label="Permalink to &quot;4. [세션 복구](./session-recovery/)&quot;">​</a></h3><p>세션 복구 메커니즘을 이해하고, 도구 호출 실패와 중단을 자동으로 처리합니다.</p><ul><li>tool_result_missing 오류 자동 처리</li><li>thinking_block_order 문제 수정</li><li>auto_resume 및 session_recovery 옵션 설정</li></ul><h3 id="_5-요청-변환-메커니즘" tabindex="-1">5. <a href="./request-transformation/">요청 변환 메커니즘</a> <a class="header-anchor" href="#_5-요청-변환-메커니즘" aria-label="Permalink to &quot;5. [요청 변환 메커니즘](./request-transformation/)&quot;">​</a></h3><p>요청 변환 메커니즘을 심층적으로 이해하고, 다양한 AI 모델 간의 프로토콜 차이를 호환합니다.</p><ul><li>Claude와 Gemini 모델의 프로토콜 차이 이해</li><li>Schema 비호환으로 인한 400 오류 해결</li><li>최적의 성능을 위한 Thinking 설정 최적화</li></ul><h3 id="_6-설정-가이드" tabindex="-1">6. <a href="./configuration-guide/">설정 가이드</a> <a class="header-anchor" href="#_6-설정-가이드" aria-label="Permalink to &quot;6. [설정 가이드](./configuration-guide/)&quot;">​</a></h3><p>모든 설정 옵션을 마스터하고, 필요에 따라 플러그인 동작을 커스터마이징합니다.</p><ul><li>설정 파일 위치 및 우선순위</li><li>모델 동작, 계정 로테이션, 애플리케이션 동작 설정</li><li>단일 계정/다중 계정/병렬 에이전트 시나리오별 권장 설정</li></ul><h3 id="_7-병렬-에이전트-최적화" tabindex="-1">7. <a href="./parallel-agents/">병렬 에이전트 최적화</a> <a class="header-anchor" href="#_7-병렬-에이전트-최적화" aria-label="Permalink to &quot;7. [병렬 에이전트 최적화](./parallel-agents/)&quot;">​</a></h3><p>병렬 에이전트 시나리오에 맞게 계정 할당을 최적화하고, PID 오프셋을 활성화합니다.</p><ul><li>병렬 에이전트 시나리오에서의 계정 충돌 문제 이해</li><li>PID 오프셋을 활성화하여 서로 다른 프로세스가 다른 계정을 우선 선택하도록 설정</li><li>round-robin 전략과 함께 다중 계정 활용률 극대화</li></ul><h3 id="_8-디버그-로그" tabindex="-1">8. <a href="./debug-logging/">디버그 로그</a> <a class="header-anchor" href="#_8-디버그-로그" aria-label="Permalink to &quot;8. [디버그 로그](./debug-logging/)&quot;">​</a></h3><p>디버그 로그를 활성화하여 문제를 해결하고 실행 상태를 모니터링합니다.</p><ul><li>디버그 로그를 활성화하여 상세 정보 기록</li><li>다양한 로그 레벨과 적용 시나리오 이해</li><li>로그 내용을 해석하여 문제를 빠르게 파악</li></ul><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>고급 기능 학습을 완료한 후:</p><ul><li>📖 <a href="./../faq/">자주 묻는 질문</a>을 참조하여 사용 중 발생하는 문제 해결</li><li>📚 <a href="./../appendix/">부록</a>을 읽고 아키텍처 설계와 전체 설정 레퍼런스 확인</li><li>🔄 <a href="./../changelog/">변경 로그</a>를 확인하여 최신 기능과 변경 사항 파악</li></ul>',32)])])}const _=i(r,[["render",o]]);export{p as __pageData,_ as default};
